FROM certificate


        AND (certificate_no LIKE CONCAT('%',#{keyword},'%') OR pet_name LIKE CONCAT('%',#{keyword},'%') OR owner_name LIKE CONCAT('%',#{keyword},'%') OR course_name LIKE CONCAT('%',#{keyword},'%'))


        AND status = #{status}


ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}

